"use client"

/**
 * Invite Source Form — create / edit a single source.
 *
 * Three kinds:
 *   - "competition": single-comp source. Requires sourceCompetitionId
 *     and globalSpots ("top N qualifies per division").
 *   - "series": series grouping. Requires sourceGroupId. No globalSpots
 *     — per-division override on the source-detail page is the only
 *     knob, so each division gets an explicit absolute total or
 *     contributes nothing.
 *   - "series_global": series-aggregate leaderboard. Requires
 *     sourceGroupId and globalSpots ("top N from the series global
 *     leaderboard per division"). Modeled distinct from "series" so
 *     each tier is its own bucket.
 *
 * The form-level validator mirrors the server-side helper: exactly one
 * of sourceCompetitionId / sourceGroupId, matched against `kind`.
 */

import { standardSchemaResolver } from "@hookform/resolvers/standard-schema"
import { useForm } from "react-hook-form"
import { z } from "zod"
import { Button } from "@/components/ui/button"
import {
  Form,
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from "@/components/ui/form"
import { Input } from "@/components/ui/input"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"
import { Textarea } from "@/components/ui/textarea"
import {
  COMPETITION_INVITE_SOURCE_KIND,
  type CompetitionInviteSource,
} from "@/db/schemas/competition-invites"

export const inviteSourceFormSchema = z
  .object({
    kind: z.enum([
      COMPETITION_INVITE_SOURCE_KIND.COMPETITION,
      COMPETITION_INVITE_SOURCE_KIND.SERIES,
      COMPETITION_INVITE_SOURCE_KIND.SERIES_GLOBAL,
    ]),
    sourceCompetitionId: z.string().optional(),
    sourceGroupId: z.string().optional(),
    globalSpots: z.number().int().positive().optional(),
    notes: z.string().max(2000).optional(),
  })
  .superRefine((val, ctx) => {
    const hasComp = !!val.sourceCompetitionId
    const hasGroup = !!val.sourceGroupId
    if (hasComp === hasGroup) {
      ctx.addIssue({
        code: z.ZodIssueCode.custom,
        message: "Pick exactly one source — a competition or a series",
        path: ["sourceCompetitionId"],
      })
    }
    if (val.kind === "competition" && !hasComp) {
      ctx.addIssue({
        code: z.ZodIssueCode.custom,
        message: "Single-competition source needs a competition",
        path: ["sourceCompetitionId"],
      })
    }
    if ((val.kind === "series" || val.kind === "series_global") && !hasGroup) {
      ctx.addIssue({
        code: z.ZodIssueCode.custom,
        message: "Series source needs a series",
        path: ["sourceGroupId"],
      })
    }
    // globalSpots required for "competition" and "series_global"; not
    // collected for "series" (per-division override is the only knob).
    if (val.kind !== "series" && !val.globalSpots) {
      ctx.addIssue({
        code: z.ZodIssueCode.custom,
        message: "Set the top-N qualifying spots per division",
        path: ["globalSpots"],
      })
    }
  })

export type InviteSourceFormValues = {
  kind: "competition" | "series" | "series_global"
  sourceCompetitionId?: string
  sourceGroupId?: string
  globalSpots?: number
  notes?: string
}

interface InviteSourceFormProps {
  defaultValues?: Partial<CompetitionInviteSource>
  competitionOptions: Array<{ id: string; name: string }>
  seriesOptions: Array<{ id: string; name: string }>
  onSubmit: (values: InviteSourceFormValues) => Promise<void> | void
  onCancel?: () => void
  submitLabel?: string
}

export function InviteSourceForm({
  defaultValues,
  competitionOptions,
  seriesOptions,
  onSubmit,
  onCancel,
  submitLabel = "Save source",
}: InviteSourceFormProps) {
  const form = useForm<InviteSourceFormValues, unknown, InviteSourceFormValues>({
    resolver: standardSchemaResolver(inviteSourceFormSchema),
    defaultValues: {
      kind:
        (defaultValues?.kind as InviteSourceFormValues["kind"]) ?? "competition",
      sourceCompetitionId: defaultValues?.sourceCompetitionId ?? undefined,
      sourceGroupId: defaultValues?.sourceGroupId ?? undefined,
      globalSpots: defaultValues?.globalSpots ?? undefined,
      notes: defaultValues?.notes ?? undefined,
    },
  })
  const kind = form.watch("kind")

  return (
    <Form {...form}>
      <form
        onSubmit={form.handleSubmit(async (v) => {
          await onSubmit(v)
        })}
        className="space-y-4"
      >
        <FormField
          control={form.control}
          name="kind"
          render={({ field }) => (
            <FormItem>
              <FormLabel>Source kind</FormLabel>
              <Select onValueChange={field.onChange} value={field.value}>
                <FormControl>
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                </FormControl>
                <SelectContent>
                  <SelectItem value="competition">Single competition</SelectItem>
                  <SelectItem value="series">Series</SelectItem>
                  <SelectItem value="series_global">
                    Series global leaderboard
                  </SelectItem>
                </SelectContent>
              </Select>
              <FormMessage />
            </FormItem>
          )}
        />

        {kind === "competition" ? (
          <FormField
            control={form.control}
            name="sourceCompetitionId"
            render={({ field }) => (
              <FormItem>
                <FormLabel>Source competition</FormLabel>
                <Select
                  onValueChange={field.onChange}
                  value={field.value ?? undefined}
                >
                  <FormControl>
                    <SelectTrigger>
                      <SelectValue placeholder="Pick a competition" />
                    </SelectTrigger>
                  </FormControl>
                  <SelectContent>
                    {competitionOptions.map((c) => (
                      <SelectItem key={c.id} value={c.id}>
                        {c.name}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
                <FormMessage />
              </FormItem>
            )}
          />
        ) : (
          <FormField
            control={form.control}
            name="sourceGroupId"
            render={({ field }) => (
              <FormItem>
                <FormLabel>Series</FormLabel>
                <Select
                  onValueChange={field.onChange}
                  value={field.value ?? undefined}
                >
                  <FormControl>
                    <SelectTrigger>
                      <SelectValue placeholder="Pick a series" />
                    </SelectTrigger>
                  </FormControl>
                  <SelectContent>
                    {seriesOptions.map((g) => (
                      <SelectItem key={g.id} value={g.id}>
                        {g.name}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
                <FormMessage />
              </FormItem>
            )}
          />
        )}

        {kind !== "series" ? (
        <FormField
          control={form.control}
          name="globalSpots"
          render={({ field }) => (
            <FormItem>
              <FormLabel>
                {kind === "series_global"
                  ? "Top N from the series global leaderboard per division"
                  : "Top N qualifies per division"}
              </FormLabel>
              <FormControl>
                <Input
                  type="number"
                  min={1}
                  value={field.value ?? ""}
                  onChange={(e) =>
                    field.onChange(
                      e.target.value === "" ? undefined : Number(e.target.value),
                    )
                  }
                />
              </FormControl>
              <FormMessage />
            </FormItem>
          )}
        />
        ) : null}

        <FormField
          control={form.control}
          name="notes"
          render={({ field }) => (
            <FormItem>
              <FormLabel>Notes</FormLabel>
              <FormControl>
                <Textarea {...field} value={field.value ?? ""} />
              </FormControl>
              <FormMessage />
            </FormItem>
          )}
        />

        <div className="flex justify-end gap-2">
          {onCancel ? (
            <Button type="button" variant="outline" onClick={onCancel}>
              Cancel
            </Button>
          ) : null}
          <Button type="submit" disabled={form.formState.isSubmitting}>
            {submitLabel}
          </Button>
        </div>
      </form>
    </Form>
  )
}

/**
 * Invite Source details page — ADR-0012 Phase 3.
 *
 * Hosts source meta editing (kind, source comp/series, default spots,
 * notes) plus the per-(championship division) allocation table where the
 * organizer overrides the source's default for specific divisions.
 *
 * The Sources tab's "Edit" button navigates here; the Add flow keeps the
 * existing dialog because there are no overrides to edit at create time.
 */
// @lat: [[competition-invites#Source details page]]

import {
  createFileRoute,
  Link,
  redirect,
  useNavigate,
  useRouter,
} from "@tanstack/react-router"
import { useServerFn } from "@tanstack/react-start"
import { ArrowLeft } from "lucide-react"
import { useMemo, useState } from "react"
import { toast } from "sonner"
import {
  InviteSourceForm,
  type InviteSourceFormValues,
} from "@/components/organizer/invites/invite-source-form"
import { Alert, AlertDescription } from "@/components/ui/alert"
import {
  Breadcrumb,
  BreadcrumbItem,
  BreadcrumbLink,
  BreadcrumbList,
  BreadcrumbPage,
  BreadcrumbSeparator,
} from "@/components/ui/breadcrumb"
import { Button } from "@/components/ui/button"
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card"
import { Checkbox } from "@/components/ui/checkbox"
import { Input } from "@/components/ui/input"
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table"
import { getCompetitionDivisionsWithCountsFn } from "@/server-fns/competition-divisions-fns"
import {
  getCompetitionGroupsFn,
  getOrganizerCompetitionsFn,
} from "@/server-fns/competition-fns"
import {
  getInviteSourceByIdFn,
  listInviteSourceAllocationsFn,
  saveInviteSourceAllocationsFn,
  updateInviteSourceFn,
} from "@/server-fns/competition-invite-fns"

export const Route = createFileRoute(
  "/compete/organizer/$competitionId/invites/sources/$sourceId",
)({
  staleTime: 10_000,
  component: InviteSourceDetailsPage,
  loader: async ({ params, context, parentMatchPromise }) => {
    const session = context.session
    if (!session?.user?.id) {
      throw redirect({
        to: "/sign-in",
        search: {
          redirect: `/compete/organizer/${params.competitionId}/invites/sources/${params.sourceId}`,
        },
      })
    }

    const parentMatch = await parentMatchPromise
    const { competition } = parentMatch.loaderData!

    // `getInviteSourceByIdFn` enforces MANAGE_COMPETITIONS on the source's
    // championship organizing team and throws when the source does not
    // exist — the parent error boundary handles both consistently.
    const [
      sourceResult,
      divisionsResult,
      allocationsResult,
      organizerCompsResult,
      organizerGroupsResult,
    ] = await Promise.all([
      getInviteSourceByIdFn({ data: { sourceId: params.sourceId } }),
      getCompetitionDivisionsWithCountsFn({
        data: {
          competitionId: params.competitionId,
          teamId: competition.organizingTeamId,
        },
      }),
      // The route-wide allocation map; we slice out this source's row
      // for the override table seed values.
      listInviteSourceAllocationsFn({
        data: { championshipCompetitionId: params.competitionId },
      }),
      getOrganizerCompetitionsFn({
        data: { teamId: competition.organizingTeamId },
      }),
      getCompetitionGroupsFn({
        data: { teamId: competition.organizingTeamId },
      }),
    ])

    // Cross-check: a source whose championship doesn't match this URL
    // should not render. The server fn already gates by championship
    // permission via `getCompetitionOrganizingTeamId`, but a URL like
    // `/compete/organizer/A/invites/sources/<sourceForB>` is a typo we
    // can stop early at the loader.
    if (
      sourceResult.source.championshipCompetitionId !== params.competitionId
    ) {
      throw new Error("Source does not belong to this competition")
    }

    const competitionOptions = (organizerCompsResult.competitions ?? [])
      .filter((c: { id: string }) => c.id !== params.competitionId)
      .map((c: { id: string; name: string }) => ({ id: c.id, name: c.name }))
    const seriesOptions = (organizerGroupsResult.groups ?? []).map(
      (g: { id: string; name: string }) => ({ id: g.id, name: g.name }),
    )

    const championshipDivisions = (divisionsResult.divisions ?? []).map(
      (d: { id: string; label: string }) => ({ id: d.id, label: d.label }),
    )

    return {
      source: sourceResult.source,
      championshipDivisions,
      allocationsBySourceByDivision:
        allocationsResult.allocationsBySourceByDivision,
      rawAllocationsForSource:
        allocationsResult.rawAllocationsBySource[params.sourceId] ?? [],
      competitionOptions,
      seriesOptions,
    }
  },
})

interface OverrideState {
  useDefault: boolean
  spots: string
}

function InviteSourceDetailsPage() {
  const {
    source,
    championshipDivisions,
    rawAllocationsForSource,
    competitionOptions,
    seriesOptions,
  } = Route.useLoaderData()
  const { competitionId } = Route.useParams()
  const router = useRouter()
  const navigate = useNavigate()

  const updateSource = useServerFn(updateInviteSourceFn)
  const saveAllocations = useServerFn(saveInviteSourceAllocationsFn)

  const [metaError, setMetaError] = useState<string | null>(null)
  const [allocationError, setAllocationError] = useState<string | null>(null)
  const [savingAllocations, setSavingAllocations] = useState(false)

  // Source default applied per-division when no override row exists.
  // Mirrors `sourceDefaultPerDivision` in the server-side allocations
  // helper:
  //   - "series": 0 (no source-level default; per-division override is
  //     the only knob).
  //   - "competition" / "series_global": source.globalSpots.
  const sourceDefaultPerDivision =
    source.kind === "series" ? 0 : (source.globalSpots ?? 0)

  // Seed the per-division override map from the raw allocation rows.
  // Presence of a row in `rawAllocationsForSource` means "override is
  // active for this division" (toggle off, spots = row.spots). Absence
  // means "uses source default" (toggle on, spots = source default for
  // display only).
  const overridesByDivisionId = useMemo(() => {
    const map = new Map<string, number>()
    for (const row of rawAllocationsForSource) {
      map.set(row.championshipDivisionId, row.spots)
    }
    return map
  }, [rawAllocationsForSource])

  const initialOverrides = useMemo<Record<string, OverrideState>>(() => {
    const out: Record<string, OverrideState> = {}
    for (const division of championshipDivisions) {
      const overrideSpots = overridesByDivisionId.get(division.id)
      if (overrideSpots !== undefined) {
        out[division.id] = {
          useDefault: false,
          spots: String(overrideSpots),
        }
      } else {
        out[division.id] = {
          useDefault: true,
          spots: String(sourceDefaultPerDivision),
        }
      }
    }
    return out
  }, [championshipDivisions, overridesByDivisionId, sourceDefaultPerDivision])

  const [overrides, setOverrides] =
    useState<Record<string, OverrideState>>(initialOverrides)

  const setRow = (divisionId: string, patch: Partial<OverrideState>) => {
    setOverrides((prev) => ({
      ...prev,
      [divisionId]: { ...prev[divisionId], ...patch },
    }))
  }

  const onMetaSubmit = async (values: InviteSourceFormValues) => {
    setMetaError(null)
    try {
      await updateSource({
        data: {
          id: source.id,
          championshipCompetitionId: competitionId,
          kind: values.kind,
          sourceCompetitionId:
            values.kind === "competition" ? values.sourceCompetitionId : null,
          sourceGroupId:
            values.kind === "series" || values.kind === "series_global"
              ? values.sourceGroupId
              : null,
          globalSpots:
            values.kind === "series" ? null : (values.globalSpots ?? null),
          notes: values.notes ?? null,
        },
      })
      toast.success("Source updated")
      router.invalidate()
    } catch (err) {
      setMetaError(err instanceof Error ? err.message : "Failed to save source")
    }
  }

  const onSaveAllocations = async () => {
    setAllocationError(null)
    // Build the allocation payload. `useDefault === true` → null (delete
    // override). `useDefault === false` → numeric value, clamped ≥ 0.
    const allocations: Array<{
      championshipDivisionId: string
      spots: number | null
    }> = []
    for (const division of championshipDivisions) {
      const row = overrides[division.id]
      if (!row) continue
      if (row.useDefault) {
        allocations.push({
          championshipDivisionId: division.id,
          spots: null,
        })
      } else {
        const trimmed = row.spots.trim()
        if (trimmed === "") {
          setAllocationError(
            `Enter a number for ${division.label} or toggle "Use default".`,
          )
          return
        }
        const parsed = Number(trimmed)
        if (!Number.isFinite(parsed) || parsed < 0 || !Number.isInteger(parsed)) {
          setAllocationError("Spots must be 0 or greater.")
          return
        }
        allocations.push({
          championshipDivisionId: division.id,
          spots: parsed,
        })
      }
    }
    setSavingAllocations(true)
    try {
      await saveAllocations({ data: { sourceId: source.id, allocations } })
      toast.success("Per-division allocations saved")
      router.invalidate()
    } catch (err) {
      setAllocationError(
        err instanceof Error ? err.message : "Failed to save allocations",
      )
    } finally {
      setSavingAllocations(false)
    }
  }

  const onDiscard = () => {
    setOverrides(initialOverrides)
    setAllocationError(null)
  }

  const sourceLabel =
    source.kind === "series"
      ? (seriesOptions.find((g) => g.id === source.sourceGroupId)?.name ??
        "Unknown series")
      : (competitionOptions.find((c) => c.id === source.sourceCompetitionId)
          ?.name ?? "Unknown competition")

  return (
    <div className="space-y-6">
      <div>
        <Breadcrumb>
          <BreadcrumbList>
            <BreadcrumbItem>
              <BreadcrumbLink asChild>
                <Link
                  to="/compete/organizer/$competitionId/invites"
                  params={{ competitionId }}
                >
                  Invites
                </Link>
              </BreadcrumbLink>
            </BreadcrumbItem>
            <BreadcrumbSeparator />
            <BreadcrumbItem>
              <BreadcrumbPage>{sourceLabel}</BreadcrumbPage>
            </BreadcrumbItem>
          </BreadcrumbList>
        </Breadcrumb>
        <div className="mt-2 flex items-center justify-between gap-3">
          <div>
            <h1 className="text-2xl font-bold tracking-tight">{sourceLabel}</h1>
            <p className="text-muted-foreground">
              Edit the source's defaults and override allocation per
              championship division.
            </p>
          </div>
          <Button
            variant="outline"
            onClick={() =>
              navigate({
                to: "/compete/organizer/$competitionId/invites",
                params: { competitionId },
              })
            }
          >
            <ArrowLeft className="mr-1 h-4 w-4" />
            Back to invites
          </Button>
        </div>
      </div>

      <Card>
        <CardHeader>
          <CardTitle>Source meta</CardTitle>
          <CardDescription>
            Kind, source competition or series, default spots, and notes.
            Already-issued invites are not affected.
          </CardDescription>
        </CardHeader>
        <CardContent>
          <InviteSourceForm
            defaultValues={source}
            competitionOptions={competitionOptions}
            seriesOptions={seriesOptions}
            onSubmit={onMetaSubmit}
            submitLabel="Save changes"
          />
          {metaError ? (
            <Alert variant="destructive" className="mt-4">
              <AlertDescription>{metaError}</AlertDescription>
            </Alert>
          ) : null}
        </CardContent>
      </Card>

      <Card>
        <CardHeader>
          <CardTitle>Per-division allocation</CardTitle>
          <CardDescription>
            Override how many spots this source contributes per championship
            division. Default is{" "}
            <span className="font-semibold">{sourceDefaultPerDivision}</span>{" "}
            per division. Toggle a row off to set an explicit value.
          </CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          {championshipDivisions.length === 0 ? (
            <div className="rounded-md border border-dashed p-6 text-center text-sm text-muted-foreground">
              This championship has no divisions yet.
            </div>
          ) : (
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>Division</TableHead>
                  <TableHead className="w-32">Resolved</TableHead>
                  <TableHead className="w-40">Use default</TableHead>
                  <TableHead className="w-40">Override spots</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {championshipDivisions.map((division) => {
                  const row = overrides[division.id]
                  if (!row) return null
                  const resolvedDisplay = row.useDefault
                    ? sourceDefaultPerDivision
                    : (() => {
                        const n = Number(row.spots)
                        return Number.isFinite(n) ? n : 0
                      })()
                  return (
                    <TableRow key={division.id}>
                      <TableCell className="font-medium">
                        {division.label}
                      </TableCell>
                      <TableCell>
                        <span
                          className={
                            row.useDefault
                              ? "text-muted-foreground"
                              : "font-semibold"
                          }
                        >
                          {resolvedDisplay}
                        </span>
                      </TableCell>
                      <TableCell>
                        <div className="flex items-center gap-2 text-sm">
                          <Checkbox
                            id={`use-default-${division.id}`}
                            checked={row.useDefault}
                            onCheckedChange={(v) =>
                              setRow(division.id, {
                                useDefault: v === true,
                                spots: row.spots,
                              })
                            }
                            aria-label={`Use default for ${division.label}`}
                          />
                          <label
                            htmlFor={`use-default-${division.id}`}
                            className="text-muted-foreground"
                          >
                            Default ({sourceDefaultPerDivision})
                          </label>
                        </div>
                      </TableCell>
                      <TableCell>
                        <Input
                          type="number"
                          min={0}
                          step={1}
                          disabled={row.useDefault}
                          value={row.spots}
                          onChange={(e) =>
                            setRow(division.id, { spots: e.target.value })
                          }
                          aria-label={`Override spots for ${division.label}`}
                        />
                      </TableCell>
                    </TableRow>
                  )
                })}
              </TableBody>
            </Table>
          )}
          {allocationError ? (
            <Alert variant="destructive">
              <AlertDescription>{allocationError}</AlertDescription>
            </Alert>
          ) : null}
          <div className="flex justify-end gap-2">
            <Button
              type="button"
              variant="outline"
              onClick={onDiscard}
              disabled={savingAllocations}
            >
              Discard
            </Button>
            <Button
              type="button"
              onClick={onSaveAllocations}
              disabled={
                savingAllocations || championshipDivisions.length === 0
              }
            >
              {savingAllocations ? "Saving..." : "Save changes"}
            </Button>
          </div>
        </CardContent>
      </Card>
    </div>
  )
}

/**
 * Championship Roster Computation
 *
 * `getChampionshipRoster` returns the union of every (sourceComp ×
 * sourceDivision) leaderboard for the championship's configured sources,
 * with each row tagged by the originating competition + division and the
 * athlete's email hydrated. The roster page renders this as a single
 * table with Competition + Division columns; client-side filters narrow
 * the view without round-tripping.
 *
 * Fan-out: a championship with K sources, each resolving to N
 * competitions × M divisions per competition, costs roughly K·N·M
 * leaderboard reads, fired in parallel. MVP organizers have 1–3 sources
 * with similarly small N/M, so the worst case is bounded under typical
 * usage. Leaderboards are cached on the public-facing render path.
 *
 * ADR-0012 Phase 6: per-(source, championshipDivision) cutoffs are
 * applied after leaderboards are fetched. The resolved allocation map
 * (`resolveSourceAllocations`) supplies the truncation N for each
 * `(sourceId, championshipDivisionId)`. Source-side `globalSpots` is
 * the per-division default when no override row exists. See ADR-0012
 * "Allocation Resolution".
 */
// @lat: [[competition-invites#Roster computation]]

import { inArray } from "drizzle-orm"
import { getDb } from "@/db"
import {
  COMPETITION_INVITE_SOURCE_KIND,
  type CompetitionInviteSource,
  type CompetitionInviteSourceKind,
} from "@/db/schemas/competition-invites"
import { competitionsTable } from "@/db/schemas/competitions"
import { scalingLevelsTable } from "@/db/schemas/scaling"
import { parseCompetitionSettings } from "@/server-fns/competition-divisions-fns"
import type { ResolvedSourceAllocations } from "./allocations"
import { getCandidatesForSourceComp } from "./candidates"
import { type DivisionMapping, listSourcesForChampionship } from "./sources"

// ============================================================================
// Types
// ============================================================================

export interface RosterRow {
  /** 1-based rank within the source competition's division leaderboard. */
  sourcePlacement: number | null
  /** Source id that produced this row. */
  sourceId: string
  /** Source kind snapshot for UI tagging. */
  sourceKind: CompetitionInviteSourceKind
  /** Comp the athlete placed at. */
  sourceCompetitionId: string
  /** Display name of the source competition. */
  sourceCompetitionName: string
  /** Division id on the source competition. */
  sourceDivisionId: string
  /** Display label of the source division (e.g. "RX Men"). */
  sourceDivisionLabel: string
  /** Stable athlete identity. `userId` may be null if the leaderboard
   *  surfaced no user id (rare); `athleteName` is always present. */
  userId: string | null
  athleteName: string
  /** Email address for the athlete, resolved from `userTable` by `userId`.
   *  Null when the leaderboard surfaced no user id (rare) or the user
   *  has no email on file. */
  athleteEmail: string | null
  /** Invite-state columns — always null at this layer; the route attaches
   *  invite status via `listActiveInvitesFn` keyed by email. */
  inviteId: null
  inviteStatus: null
  roundId: null
  roundNumber: null
}

export interface GetChampionshipRosterInput {
  championshipId: string
}

// ============================================================================
// Internal helpers
// ============================================================================

interface SourceCompetitionRef {
  sourceId: string
  sourceKind: CompetitionInviteSourceKind
  competitionId: string
  competitionName: string
}

interface DivisionRef {
  competitionId: string
  competitionName: string
  divisionId: string
  divisionLabel: string
  sourceId: string
  sourceKind: CompetitionInviteSourceKind
}

interface ChampionshipDivisionInfo {
  id: string
  label: string
}

/**
 * Parse a source's `divisionMappings` JSON column into a typed array.
 *
 * The column is `text` storing
 * `[{ sourceDivisionId, championshipDivisionId, spots? }]`. Returns an
 * empty array on null / malformed JSON — the caller falls back to label
 * matching, which is the common case for organizers who haven't filled
 * in mappings yet.
 */
function parseDivisionMappings(
  raw: string | null | undefined,
): DivisionMapping[] {
  if (!raw) return []
  try {
    const parsed = JSON.parse(raw)
    if (!Array.isArray(parsed)) return []
    return parsed.filter(
      (m): m is DivisionMapping =>
        typeof m === "object" &&
        m !== null &&
        typeof (m as { sourceDivisionId?: unknown }).sourceDivisionId ===
          "string" &&
        typeof (m as { championshipDivisionId?: unknown })
          .championshipDivisionId === "string",
    )
  } catch {
    return []
  }
}

/**
 * Map a source-side division id to its championship-division counterpart.
 *
 * Resolution order:
 *   1. Explicit row in the source's `divisionMappings` JSON.
 *   2. Label match against the championship's divisions
 *      (case-insensitive, trimmed) — covers the common case where the
 *      source comp uses the same division labels as the championship.
 *
 * Returns `null` when no mapping can be inferred. Callers use that as
 * the signal to skip the cutoff (i.e. include all leaderboard rows) so
 * mis-mapped divisions don't silently drop qualifying athletes.
 */
function mapSourceDivisionToChampionship(args: {
  sourceDivisionId: string
  sourceDivisionLabel: string
  divisionMappings: DivisionMapping[]
  championshipDivisions: ReadonlyArray<ChampionshipDivisionInfo>
}): string | null {
  const explicit = args.divisionMappings.find(
    (m) => m.sourceDivisionId === args.sourceDivisionId,
  )
  if (explicit) return explicit.championshipDivisionId

  const normalized = args.sourceDivisionLabel.trim().toLowerCase()
  const matched = args.championshipDivisions.find(
    (d) => d.label.trim().toLowerCase() === normalized,
  )
  return matched ? matched.id : null
}

/**
 * Resolve the (competitionId, name) tuples each source contributes:
 * single-comp source → 1 row; series source → every comp in the group.
 *
 * Returns a deduped list keyed by `competitionId` so a comp referenced
 * by both a direct source AND a series source only fetches once. The
 * first-encountered source wins for tagging.
 */
async function resolveSourceCompetitions(
  championshipId: string,
): Promise<{
  sources: CompetitionInviteSource[]
  refs: SourceCompetitionRef[]
  seriesCompCountBySourceId: Map<string, number>
}> {
  const sources = await listSourcesForChampionship(championshipId)
  if (sources.length === 0) {
    return { sources: [], refs: [], seriesCompCountBySourceId: new Map() }
  }

  const db = getDb()

  // Collect all comp ids we need to look up.
  const directIds = sources
    .filter(
      (s): s is typeof s & { sourceCompetitionId: string } =>
        s.kind === "competition" && !!s.sourceCompetitionId,
    )
    .map((s) => s.sourceCompetitionId)
  const groupIds = sources
    .filter(
      (s): s is typeof s & { sourceGroupId: string } =>
        (s.kind === "series" || s.kind === "series_global") &&
        !!s.sourceGroupId,
    )
    .map((s) => s.sourceGroupId)

  // One query per category; each can be empty.
  const [directComps, seriesComps] = await Promise.all([
    directIds.length > 0
      ? db
          .select({
            id: competitionsTable.id,
            name: competitionsTable.name,
            groupId: competitionsTable.groupId,
          })
          .from(competitionsTable)
          .where(inArray(competitionsTable.id, directIds))
      : Promise.resolve(
          [] as Array<{ id: string; name: string; groupId: string | null }>,
        ),
    groupIds.length > 0
      ? db
          .select({
            id: competitionsTable.id,
            name: competitionsTable.name,
            groupId: competitionsTable.groupId,
          })
          .from(competitionsTable)
          .where(inArray(competitionsTable.groupId, groupIds))
      : Promise.resolve(
          [] as Array<{ id: string; name: string; groupId: string | null }>,
        ),
  ])

  const refs: SourceCompetitionRef[] = []
  const seen = new Set<string>()
  const seriesCompCountBySourceId = new Map<string, number>()

  for (const source of sources) {
    if (source.kind === "competition" && source.sourceCompetitionId) {
      if (seen.has(source.sourceCompetitionId)) continue
      const row = directComps.find((c) => c.id === source.sourceCompetitionId)
      if (!row) continue
      seen.add(source.sourceCompetitionId)
      refs.push({
        sourceId: source.id,
        sourceKind: source.kind,
        competitionId: row.id,
        competitionName: row.name,
      })
    } else if (
      (source.kind === "series" || source.kind === "series_global") &&
      source.sourceGroupId
    ) {
      const matchingComps = seriesComps.filter(
        (c) => c.groupId === source.sourceGroupId,
      )
      seriesCompCountBySourceId.set(source.id, matchingComps.length)
      for (const c of matchingComps) {
        if (seen.has(c.id)) continue
        seen.add(c.id)
        refs.push({
          sourceId: source.id,
          sourceKind: source.kind,
          competitionId: c.id,
          competitionName: c.name,
        })
      }
    }
  }
  return { sources, refs, seriesCompCountBySourceId }
}

/**
 * Resolve every (competition, division) pair to fetch a leaderboard
 * for. Reads `competitionsTable.settings` to find each comp's scaling
 * group, then resolves levels in one batched query.
 */
async function resolveDivisionRefs(
  comps: SourceCompetitionRef[],
): Promise<DivisionRef[]> {
  if (comps.length === 0) return []

  const db = getDb()
  const compSettings = await db
    .select({ id: competitionsTable.id, settings: competitionsTable.settings })
    .from(competitionsTable)
    .where(
      inArray(
        competitionsTable.id,
        comps.map((c) => c.competitionId),
      ),
    )

  const scalingGroupByComp = new Map<string, string>()
  for (const row of compSettings) {
    const settings = parseCompetitionSettings(row.settings)
    const sgid = settings?.divisions?.scalingGroupId
    if (sgid) scalingGroupByComp.set(row.id, sgid)
  }

  const allGroupIds = Array.from(new Set(scalingGroupByComp.values()))
  if (allGroupIds.length === 0) return []

  const levels = await db
    .select({
      id: scalingLevelsTable.id,
      label: scalingLevelsTable.label,
      scalingGroupId: scalingLevelsTable.scalingGroupId,
      position: scalingLevelsTable.position,
    })
    .from(scalingLevelsTable)
    .where(inArray(scalingLevelsTable.scalingGroupId, allGroupIds))

  const levelsByGroup = new Map<
    string,
    Array<{ id: string; label: string; position: number }>
  >()
  for (const lvl of levels) {
    const arr = levelsByGroup.get(lvl.scalingGroupId) ?? []
    arr.push({ id: lvl.id, label: lvl.label, position: lvl.position })
    levelsByGroup.set(lvl.scalingGroupId, arr)
  }
  for (const arr of levelsByGroup.values()) {
    arr.sort((a, b) => a.position - b.position)
  }

  const out: DivisionRef[] = []
  for (const comp of comps) {
    const sgid = scalingGroupByComp.get(comp.competitionId)
    if (!sgid) continue
    const compLevels = levelsByGroup.get(sgid) ?? []
    for (const lvl of compLevels) {
      out.push({
        competitionId: comp.competitionId,
        competitionName: comp.competitionName,
        divisionId: lvl.id,
        divisionLabel: lvl.label,
        sourceId: comp.sourceId,
        sourceKind: comp.sourceKind,
      })
    }
  }
  return out
}

/**
 * Compute the cutoff (max number of qualifying placements) for a
 * leaderboard fetched for `(source, sourceCompetitionId, sourceDivisionId)`.
 *
 * Single-comp source: the cutoff is the resolved per-(source,
 * championshipDivision) value. Override present → uses override; absent
 * → uses the source's `globalSpots` default (applied per division).
 *
 * Series source: keeps the full leaderboard (no cutoff). The per-
 * (source, division) allocation still gates invite issuing and claim
 * acceptance via `divisionAllocationTotals`; the leaderboard fan-out
 * just doesn't pre-truncate so organizers can pick whom to invite from
 * the full candidate pool.
 *
 * Returns `null` when no cutoff applies (i.e. include every row).
 */
function computeCutoffForLeaderboard(args: {
  source: CompetitionInviteSource
  sourceDivisionId: string
  sourceDivisionLabel: string
  championshipDivisions: ReadonlyArray<ChampionshipDivisionInfo>
  resolved: ResolvedSourceAllocations
  divisionMappings: DivisionMapping[]
}): number | null {
  if (args.source.kind === COMPETITION_INVITE_SOURCE_KIND.SERIES) {
    return null
  }

  // Single-comp source: cutoff is the resolved spots for the mapped
  // championship division. If we can't infer the championship division,
  // fall back to no truncation so we don't accidentally drop qualifying
  // athletes — the downstream UI still surfaces the correct denominator.
  const championshipDivisionId = mapSourceDivisionToChampionship({
    sourceDivisionId: args.sourceDivisionId,
    sourceDivisionLabel: args.sourceDivisionLabel,
    divisionMappings: args.divisionMappings,
    championshipDivisions: args.championshipDivisions,
  })
  if (championshipDivisionId === null) return null
  const spots = args.resolved.byDivision[championshipDivisionId]
  if (spots === undefined) return null
  return spots
}

// ============================================================================
// Main entry
// ============================================================================

export async function getChampionshipRoster(
  input: GetChampionshipRosterInput,
): Promise<{ rows: RosterRow[] }> {
  const { refs: comps } = await resolveSourceCompetitions(input.championshipId)
  if (comps.length === 0) return { rows: [] }

  const divisionRefs = await resolveDivisionRefs(comps)
  if (divisionRefs.length === 0) return { rows: [] }

  // Fan out per (sourceComp × division) candidate fetches in parallel.
  // `getCandidatesForSourceComp` is purpose-built for this surface: it
  // returns active registrations directly, with no heat / event-status /
  // publication gating. The roster used to call `getCompetitionLeaderboard`
  // here, which silently dropped divisions whose athletes hadn't been
  // heat-assigned — see docs/bugs/0001-invite-candidates-missing-divisions.md.
  //
  // Cutoff is allocation budget metadata, not a candidate filter. The
  // organizer needs every eligible athlete on the page so they can pick
  // whom to invite — `entries.slice(0, cutoff)` previously dropped
  // eligible candidates whenever the source had more registrants than
  // the championship-division allocation. The denominator math lives in
  // `divisionAllocationTotals` outside this fan-out.
  const candidates = await Promise.all(
    divisionRefs.map((ref) =>
      getCandidatesForSourceComp({
        competitionId: ref.competitionId,
        divisionId: ref.divisionId,
      }).then((c) => ({ ref, entries: c.entries })),
    ),
  )

  const rows: RosterRow[] = []
  for (const { ref, entries } of candidates) {
    entries.forEach((e, idx) => {
      rows.push({
        sourcePlacement: idx + 1,
        sourceId: ref.sourceId,
        sourceKind: ref.sourceKind,
        sourceCompetitionId: ref.competitionId,
        sourceCompetitionName: ref.competitionName,
        sourceDivisionId: ref.divisionId,
        sourceDivisionLabel: ref.divisionLabel,
        userId: e.userId,
        athleteName: e.athleteName,
        athleteEmail: e.athleteEmail,
        inviteId: null,
        inviteStatus: null,
        roundId: null,
        roundNumber: null,
      })
    })
  }

  return { rows }
}

